  ('874c5a66-d7e6-4c03-9886-4faf284c7faf', $$Scheikunde$$, $$VWO$$, $$Cadmiumgeel$$, $$VWO Scheikunde 2022-II$$),
  ('d9ad7f03-526a-4e52-90e0-0fd7c02ff730', $$Scheikunde$$, $$VWO$$, $$Merox$$, $$VWO Scheikunde 2022-II$$),
  ('4333ac2f-7634-4431-ab1c-cc3f891ad404', $$Scheikunde$$, $$VWO$$, $$EPDM-rubber$$, $$VWO Scheikunde 2022-II$$),
