insert into practice_context_blocks (id, exercise_id, label, image_url, text_content, block_type) values
  ('da96ea1c-1531-497d-86e1-863dc1bf6135', '874c5a66-d7e6-4c03-9886-4faf284c7faf', $$cadmiumgeel en cadmiumcarbonaat (inleiding)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context1.png$$,
   $$In de negentiende en begin twintigste eeuw werden door de chemische industrie veel nieuwe pigmenten ontwikkeld, zoals cadmiumgeel (cadmiumsulfide, CdS). Cadmiumgeel werd onder andere gemaakt door de reactie van cadmiumcarbonaat met zwavel (S). Bij deze reactie ontstaan behalve cadmiumsulfide ook zwaveldioxide en koolstofdioxide.$$, 'inline'),
  ('a84b2616-09c0-4bb7-bdfb-09f0283c30fb', '874c5a66-d7e6-4c03-9886-4faf284c7faf', $$zwavel in overmaat — scheiding door verwarmen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context2.png$$,
   $$Bij deze productie werd zwavel in overmaat toegevoegd. De overgebleven zwavel kon na afloop van de reactie gemakkelijk worden gescheiden van de gevormde cadmiumsulfide door het verkregen mengsel te verwarmen. Hierbij verdampt de zwavel maar de cadmiumsulfide niet.$$, 'inline'),
  ('cbd70a34-3ca0-463b-8fb2-e6d132847d3a', '874c5a66-d7e6-4c03-9886-4faf284c7faf', $$drie aantastingen van cadmiumgeel op schilderijen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context3.png$$,
   $$Helaas bleek cadmiumgeel op de lange termijn niet chemisch stabiel. Op verschillende schilderijen zijn drie opeenvolgende aantastingen van cadmiumgeel waargenomen:
− verbleking door de vorming van cadmiumsulfaat.
− de vorming van kleine witte vlekken waarin vooral cadmiumsulfaatmonohydraat aanwezig is.
− verkleuring door onder andere de vorming van lood(II)sulfaat PbSO₄. Deze verkleuring trad alleen op nadat vernis was aangebracht op een al aangetast schilderij.$$, 'inline'),
  ('921fbfdd-039e-4eba-9b60-cdee131f6e31', '874c5a66-d7e6-4c03-9886-4faf284c7faf', $$omzetting tot cadmiumsulfaatmonohydraat (vochtige lucht)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context4.png$$,
   $$De omzetting van cadmiumgeel met zuurstof tot cadmiumsulfaatmonohydraat treedt alleen op in vochtige lucht.$$, 'inline'),
  ('c7e5eca6-d2d5-476b-bf33-064bdc31a848', '874c5a66-d7e6-4c03-9886-4faf284c7faf', $$gevonden zout met cadmium- en sulfaationen (2:3)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context5.png$$,
   $$Behalve cadmiumsulfaatmonohydraat ontdekte men in de witte vlekken een ander zout. In dit zout zijn cadmiumionen en sulfaationen in de molverhouding 2 : 3 aanwezig. Behalve deze ionen is er nog één andere ionsoort aanwezig. Op grond van de gevonden samenstelling van het zout vermoedden de onderzoekers dat een van de schilderijen ooit met een oplossing van ammoniak is schoongemaakt.$$, 'inline'),
  ('5a6d226d-de77-48bd-afa4-30c9ebc2f487', '874c5a66-d7e6-4c03-9886-4faf284c7faf', $$evenwicht CdSO4 in de verflaag (Ks)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context6.png$$,
   $$Tijdens periodes met hoge luchtvochtigheid lossen de zouten die in een verflaag aanwezig zijn enigszins op. Dit wordt veroorzaakt doordat zich dan bijvoorbeeld het evenwicht CdSO₄ ⇌ Cd²⁺ + SO₄²⁻ kan instellen in de verflaag. De gehydrateerde ionen kunnen vervolgens door verf- en vernislagen heen bewegen. Voor het evenwicht CdSO₄ ⇌ Cd²⁺ + SO₄²⁻ geldt Ks = [Cd²⁺][SO₄²⁻]. Ks is het zogenoemde oplosbaarheidsproduct. De waardes van Ks van enkele stoffen zijn in de tabel gegeven.$$, 'inline'),
  ('337e2188-e2c3-4a38-83d3-a3ba976a2854', '874c5a66-d7e6-4c03-9886-4faf284c7faf', $$tabel — oplosbaarheidsproducten (Ks)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context7.png$$,
   $$tabel: oplosbaarheidsproducten. cadmiumsulfaat CdSO₄, Ks = [Cd²⁺][SO₄²⁻], waarde 5,3·10⁻¹; lood(II)sulfaat PbSO₄, Ks = [Pb²⁺][SO₄²⁻], waarde 1,7·10⁻⁸; lood(II)ethanoaat Pb(CH₃COO)₂, Ks = [Pb²⁺][CH₃COO⁻]², waarde 2·10¹.$$, 'inline'),
  ('ecba17c7-eae8-46ce-8aaa-623785f0e9bb', '874c5a66-d7e6-4c03-9886-4faf284c7faf', $$vernis met lood(II)ethanoaat — PbSO4 aangetroffen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context8.png$$,
   $$Op een schilderij waar het cadmiumgeel al deels was omgezet tot cadmiumsulfaat is in het verleden een laag vernis aangebracht. De gebruikte vernis bevatte als enige loodverbinding lood(II)ethanoaat (Pb(CH₃COO)₂). Zowel in de verflaag als in de vernislaag is door de onderzoekers vast lood(II)sulfaat (PbSO₄) aangetroffen.$$, 'inline'),
  ('fa4d94be-06ee-48ff-a289-a785cb5ec4b1', 'd9ad7f03-526a-4e52-90e0-0fd7c02ff730', $$Merox-proces inleiding (R–SH definitie)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context1.png$$,
   $$Het Merox-proces is een industrieel proces om zwavelhoudende verbindingen te verwijderen uit aardolieproducten zoals lpg. Lpg is een mengsel van koolwaterstoffen met een laag kookpunt. De zwavelhoudende verbindingen kunnen worden aangeduid met R–SH, waarbij de groep R staat voor een koolwaterstofketen. In figuur 1 is het blokschema van het Merox-proces onvolledig weergegeven.$$, 'inline'),
  ('945681b5-7e82-4fea-ada8-d36b0cb99c43', 'd9ad7f03-526a-4e52-90e0-0fd7c02ff730', $$figuur 1 — blokschema Merox-proces$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context2.png$$,
   $$figuur 1: onvolledig blokschema van het Merox-proces. Instroom natronloog en onzuiver lpg naar reactor 1 (R1); R1 met uitgaande stofstroom lpg (naar boven) en een stroom natronloog + NaRS-oplossing naar reactor 2 (R2); R2 met een uitgaande stofstroom aangeduid met *.$$, 'inline'),
  ('5c8d1192-ad42-48c1-bbc2-f71cc3e28d0c', 'd9ad7f03-526a-4e52-90e0-0fd7c02ff730', $$scheiding in R1 — reactie 1$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context3.png$$,
   $$Het is niet mogelijk om lpg en R–SH te scheiden met behulp van water. Daarom wordt het gasvormige, nog onzuivere lpg in reactor 1 (R1) in contact gebracht met een overmaat natronloog. In R1 reageren de zwavelhoudende verbindingen volgens reactie 1.

reactie 1: R–SH (g) + OH⁻ (aq) → R–S⁻ (aq) + H₂O (l)$$, 'inline'),
  ('08f0184e-42f6-4ec8-aed3-601914a56858', 'd9ad7f03-526a-4e52-90e0-0fd7c02ff730', $$waterstofbrugvorming in basische oplossing$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context4.png$$,
   $$In een basische oplossing kunnen de zwavelhoudende verbindingen wel van het lpg worden afgescheiden. Dit wordt veroorzaakt door de vorming van bindingen tussen watermoleculen en deeltjes die in R1 zijn ontstaan.$$, 'inline'),
  ('b09fd788-0429-4c00-8bc4-e1c9c8345a67', 'd9ad7f03-526a-4e52-90e0-0fd7c02ff730', $$van R1 naar R2 — totaalvergelijking$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context5.png$$,
   $$Het reactiemengsel wordt onderin R1 afgetapt en doorgevoerd naar reactor 2 (R2). In R2 wordt een overmaat lucht door de oplossing afkomstig van R1 geleid, waarbij disulfides (R–S–S–R) worden gevormd. De totaalvergelijking van de reacties die in R1 en R2 verlopen, is hieronder weergegeven.

totaalreactie: 4 R–SH + O₂ → 2 R–S–S–R + 2 H₂O$$, 'inline'),
  ('9626e0ef-c22d-4450-ad64-6de09328054e', 'd9ad7f03-526a-4e52-90e0-0fd7c02ff730', $$omzettingssnelheid butaanthiol — inleiding$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context6.png$$,
   $$In een onderzoek is de omzettingssnelheid van R–SH tot R–S–S–R nader onderzocht. Men onderzocht de omzetting van butaanthiol (C₄H₁₀S) in natronloog. Hierbij werd op verschillende tijdstippen de fractie [C₄H₁₀S]t / [C₄H₁₀S]₀ bepaald. In figuur 2 zijn de resultaten van een meting weergegeven.$$, 'inline'),
  ('90b43e4a-17f1-48d6-9111-6243682892ce', 'd9ad7f03-526a-4e52-90e0-0fd7c02ff730', $$figuur 2 — fractie butaanthiol tegen tijd$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context7.png$$,
   $$figuur 2: grafiek van [C₄H₁₀S]t / [C₄H₁₀S]₀ (verticale as, 0 tot 1,00) tegen tijd in uren (horizontale as, 0 tot 10). De curve daalt exponentieel vanaf 1,00 bij t = 0 tot ongeveer 0,40 bij t = 2,0 h, en verder tot ongeveer 0,04 bij t ≈ 8,7 h.$$, 'inline'),
  ('5a18e3c5-3439-4080-ad6f-f1fb4d3a15ad', 'd9ad7f03-526a-4e52-90e0-0fd7c02ff730', $$beginconcentratie en dichtheid reactiemengsel$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context8.png$$,
   $$Op t = 0 bevatte het mengsel 372 massa-ppm butaanthiol. De molaire massa van butaanthiol is 90,2 g mol⁻¹. De dichtheid van het reactiemengsel was 0,75 kg L⁻¹.$$, 'inline'),
  ('c43ab995-262c-4779-b564-63b2f25a09f4', 'd9ad7f03-526a-4e52-90e0-0fd7c02ff730', $$scheidingsruimte 1 (S1) — hergebruik natronloog$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context9.png$$,
   $$In scheidingsruimte 1 (S1) wordt het vloeibare mengsel afkomstig uit R2 gescheiden. De laag met daarin de vloeibare disulfides (R–S–S–R) wordt als afval afgevoerd. De laag met natronloog bevat geen organische stoffen, zodat het natronloog kan worden hergebruikt in het proces. Om de reactie in R1 steeds onder gelijke omstandigheden te laten verlopen, moet het natronloog een bewerking ondergaan voordat het kan worden teruggevoerd.$$, 'inline'),
  ('40f37add-3ca6-40f6-bdf6-dd008c5ef4aa', 'd9ad7f03-526a-4e52-90e0-0fd7c02ff730', $$uitwerkbijlage vraag 12 — blokschema Merox-proces$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context10.png$$,
   $$uitwerkbijlage bij vraag 12: hetzelfde onvolledige blokschema als figuur 1 (instroom natronloog en onzuiver lpg naar R1; R1 met uitgaande stroom lpg en een stroom natronloog + NaRS-oplossing naar R2; R2 met een uitgaande stroom aangeduid met *), met ruime witruimte om de ontbrekende scheidingsruimte(n) en stofstromen in te tekenen.$$, 'uitwerkbijlage'),
  ('7aa8e786-010d-45ad-8fe7-e8183b1a8005', '4333ac2f-7634-4431-ab1c-cc3f891ad404', $$EPDM-rubber inleiding + structuurformule ENB$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context1.png$$,
   $$EPDM-rubber is een synthetische rubbersoort, die veel wordt gebruikt in de auto-industrie voor bijvoorbeeld afdichtingsstrips en raamrubbers. Bij de productie van EPDM-rubber wordt eerst thermoplastisch EPDM (t-EPDM) gemaakt. Hierbij ondergaat een mengsel van etheen, propeen en een zogeheten dieen een additie-polymerisatie. Een veelgebruikt dieen hierbij is ethylideennorborneen (ENB). De structuurformule van ENB is hiernaast weergegeven (een vijfring met een C=C-dubbele binding in de ring en een zijketen –CH=CH-CH₃ aan de ring). Bij de vorming van t-EPDM reageert alleen de C=C-binding die zich in de ring bevindt.$$, 'inline'),
  ('8130899a-7424-40f8-a41e-52a434e355b6', '4333ac2f-7634-4431-ab1c-cc3f891ad404', $$katalysatortypes 1 en 2 — kristallijne gebieden$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context2.png$$,
   $$De polymerisatie tot t-EPDM verloopt onder invloed van een katalysator. Er zijn twee types katalysator beschikbaar:
− Type 1: hiermee wordt de vorming van een willekeurig (random) copolymeer bevorderd;
− Type 2: hiermee wordt de vorming van een blok-copolymeer bevorderd.
Het blijkt dat de keuze van het type katalysator een sterke invloed heeft op de vorming van kristallijne gebieden in het t-EPDM. In een kristallijn gebied vertonen de polymeerketens een grote mate van ordening. In t-EPDM zijn geen crosslinks aanwezig tussen de polymeerketens.$$, 'inline'),
  ('cc8feedf-7b56-4991-978e-f65971e02a75', '4333ac2f-7634-4431-ab1c-cc3f891ad404', $$vervormbaarheid vs kristallijne gebieden$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context3.png$$,
   $$De vervormbaarheid van t-EPDM wordt minder naarmate het materiaal meer kristallijne gebieden bevat.$$, 'inline'),
  ('991e5cab-3f0f-4edb-99e2-69709163eb6d', '4333ac2f-7634-4431-ab1c-cc3f891ad404', $$t-EPDM naar EPDM-rubber — bio-ethanol, reactie 1$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context4.png$$,
   $$Het t-EPDM wordt vervolgens omgezet tot het eindproduct EPDM-rubber. Tot voor kort werd EPDM-rubber geproduceerd op basis van fossiele grondstoffen. In Brazilië gebruikt men nu bio-ethanol uit suikerriet in plaats van aardolie als grondstof voor het benodigde etheen. De omzetting van ethanol tot etheen is hieronder weergegeven.

reactie 1: C₂H₆O (l) → C₂H₄ (g) + H₂O (l)$$, 'inline'),
  ('92eca182-78bc-4430-940d-acc9c6f0ff6e', '4333ac2f-7634-4431-ab1c-cc3f891ad404', $$Keltan-Eco en ¹⁴C-gehalte$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context5.png$$,
   $$Het etheen afkomstig uit reactie 1 wordt vervolgens gebruikt om EPDM-rubber te produceren onder de merknaam Keltan®-Eco. Biogebaseerde producten worden gecontroleerd om misbruik van belastingvoordelen te voorkomen. Hiertoe wordt het gehalte ¹⁴C-atomen in het product bepaald. ¹⁴C-atomen worden in de atmosfeer door kosmische straling gevormd uit ¹⁴N-atomen. Uit de ¹⁴C-atomen wordt in de atmosfeer snel ¹⁴CO₂ gevormd. Het gehalte ¹⁴C in de atmosfeer is constant. Het gehalte ¹⁴C in biomassa bedraagt hierdoor gemiddeld 1,5·10⁻⁶ ppm van alle C-atomen. De ¹⁴C-atomen worden in de loop van de tijd door radioactief verval omgezet tot ¹⁴N-atomen.$$, 'inline'),
  ('ab78dbed-09a0-48ab-8710-4bc8f4fc4310', '4333ac2f-7634-4431-ab1c-cc3f891ad404', $$reactie 1 is endotherm$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context6.png$$,
   $$Reactie 1 is endotherm. De benodigde warmte wordt in het proces geleverd door verbranding van de resten van het suikerriet.$$, 'inline'),
  ('ed280bf7-cb07-4afa-8517-aaed4f2a08a2', '4333ac2f-7634-4431-ab1c-cc3f891ad404', $$omzetting aan aluminiumoxide-katalysator oppervlak$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context7.png$$,
   $$De omzetting van ethanol tot etheen vindt plaats aan het oppervlak van een aluminiumoxide-katalysator. Op de uitwerkbijlage is een deel van het oppervlak weergegeven. Uit onderzoek is gebleken dat de OH-groepen en de O⁻-groepen aan het oppervlak een belangrijke rol spelen in de katalytische werking. Men vermoedt dat hierbij waterstofbruggen worden gevormd tussen moleculen ethanol en de aanwezige groepen op het oppervlak.$$, 'inline'),
  ('ff8dbac0-148f-4370-a07c-df77e634cc73', '4333ac2f-7634-4431-ab1c-cc3f891ad404', $$molverhoudingen monomeereenheden Keltan-Eco$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context8.png$$,
   $$Per mol monomeereenheden van Keltan®-Eco is gemiddeld 0,55 mol etheen, 0,40 mol propeen (C₃H₆) en 0,050 mol ENB aanwezig.$$, 'inline'),
  ('35703a2d-59f9-4c52-be89-f9edf51537c5', '4333ac2f-7634-4431-ab1c-cc3f891ad404', $$uitwerkbijlage vraag 18 — katalysatoroppervlak$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context9.png$$,
   $$uitwerkbijlage bij vraag 18: gedeelte van het oppervlak van de aluminiumoxide-katalysator, met vier Al-atomen aan het oppervlak, waarvan twee met een OH-groep en twee met een O⁻-groep (zonder H). De kandidaat moet een molecuul ethanol tekenen dat met twee waterstofbruggen (stippellijnen) aan het oppervlak gebonden is.$$, 'uitwerkbijlage'),
  ('39446b8a-1a4f-493d-b107-4c4408e2dca4', 'acda46bd-f2b7-40ab-bf46-332fcd744f86', $$transglutaminase (TG) — koppeling restgroepen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context1.png$$,
   $$In de voedselindustrie wordt soms het enzym transglutaminase (TG) gebruikt om reststukjes vlees aan elkaar te lijmen tot grotere stukken. Het enzym katalyseert de koppeling van de restgroepen van de aminozuureenheden glutamine en lysine die aanwezig zijn in peptideketens.$$, 'inline'),
  ('74268463-44b3-4a91-b8e7-9eb5554f89ac', 'acda46bd-f2b7-40ab-bf46-332fcd744f86', $$figuur 1 inleiding — koppeling glutamine/lysine$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context2.png$$,
   $$In figuur 1 is de koppeling van de restgroepen van een glutamine-eenheid en een lysine-eenheid in verschillende peptideketens schematisch en onvolledig weergegeven.$$, 'inline'),
  ('a06623e5-d83a-40b3-a476-05ca61a9878c', 'acda46bd-f2b7-40ab-bf46-332fcd744f86', $$figuur 1 — koppelingsreactie glutamine + lysine ⇌ ... + X$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context3.png$$,
   $$figuur 1: ~CH₂-CH₂-C(=O)-NH₂ (glutamine-eenheid) + H₃N⁺-CH₂~ (lysine-eenheid) ⇌ ~CH₂-CH₂-C(=O)-N(H)-CH₂~ + X.$$, 'inline'),
  ('f7b7ae9f-96e1-4253-af2a-3f370ab0d87b', 'acda46bd-f2b7-40ab-bf46-332fcd744f86', $$TG-reactie met water — vorming ammoniak$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context4.png$$,
   $$Wanneer geen lysine-restgroepen of ongebonden aminozuren beschikbaar zijn, katalyseert TG ook de reactie tussen de restgroep van glutamine-eenheden en water. Hierbij wordt een andere aminozuur-eenheid gevormd en ontstaat ammoniak. Deze omzetting is op de uitwerkbijlage onvolledig weergegeven.$$, 'inline'),
  ('07f76147-f6d5-4d9b-bb70-836097b55da5', 'acda46bd-f2b7-40ab-bf46-332fcd744f86', $$pH-afhankelijkheid koppeling — Kz van ~NH3+$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context5.png$$,
   $$De koppeling die in de figuur is weergegeven, verloopt in een breed pH-gebied. De reactie verloopt alleen als de restgroep van de lysine-eenheid positief geladen is. Bij de gemiddelde pH van bloed zijn de aminogroepen in de restgroepen van lysine-eenheden grotendeels omgezet tot ~NH₃⁺-groepen. De waarde van de Kz van de NH₃⁺-groep is 6,3·10⁻¹¹.$$, 'inline'),
  ('5d022835-5326-4200-92f1-d3dc745959a2', 'acda46bd-f2b7-40ab-bf46-332fcd744f86', $$NH2-groep glutamine vs lysine — grensstructuur$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context6.png$$,
   $$De NH₂-groep in de restgroep van glutamine is een veel zwakkere base dan de NH₂-groep in de restgroep van lysine. Dit kan worden verklaard met behulp van een grensstructuur van de restgroep van glutamine. In deze grensstructuur komen formele ladingen voor. Op de uitwerkbijlage is deze grensstructuur onvolledig weergegeven.$$, 'inline'),
  ('1f0e1289-7119-411c-ae9d-72dea4797b32', 'acda46bd-f2b7-40ab-bf46-332fcd744f86', $$reactiemechanisme TG — His373 en Cys314$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context7.png$$,
   $$In het reactiemechanisme van de koppeling van glutamine en lysine door TG spelen twee aminozuureenheden in het actieve centrum van TG een rol: His373 en Cys314. Op de uitwerkbijlage is een stap uit dit mechanisme onvolledig weergegeven. In deze stap wordt een eenheid Lys gekoppeld aan een eenheid Gln die al aan aminozuureenheid Cys314 van TG was gekoppeld.$$, 'inline'),
  ('5e6f6452-42ff-4a31-847a-6d83bc027341', 'acda46bd-f2b7-40ab-bf46-332fcd744f86', $$uitwerkbijlage vraag 22 — reactie glutamine + water$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context8.png$$,
   $$uitwerkbijlage bij vraag 22: onvolledige vergelijking ~CH₂-CH₂-C(=O)-NH₂ (glutamine-eenheid) + ... → ... + ..., met stippellijnen voor de ontbrekende reactant, de gevormde aminozuur-eenheid en de andere gevormde stof, en een stippellijn achter 'ontstane aminozuureenheid:' voor de naam.$$, 'uitwerkbijlage'),
  ('bc2da2d6-a57e-46c0-ad2d-978966c79fc8', 'acda46bd-f2b7-40ab-bf46-332fcd744f86', $$uitwerkbijlage vraag 24 — grensstructuur restgroep glutamine$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context9.png$$,
   $$uitwerkbijlage bij vraag 24: gegeven structuurformule van de restgroep glutamine (~CH₂-CH₂-C(=O)-N(H)-H, neutrale vorm), met ruime witruimte ernaast om de grensstructuur met formele ladingen en de ontbrekende niet-bindende elektronenparen te tekenen.$$, 'uitwerkbijlage'),
  ('b8e1e27e-d521-48d4-8788-fd535117c55d', 'acda46bd-f2b7-40ab-bf46-332fcd744f86', $$uitwerkbijlage vraag 25 — reactiemechanisme His373/Cys314$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context10.png$$,
   $$uitwerkbijlage bij vraag 25: onvolledig reactiemechanisme met links de restgroepen van His373 (imidazoolring met N-H) en Cys314 (S-C(=O)-Gln) en de restgroep van Lys (H₂N-H), en rechts (na de pijl) het product met de imidazoolring van His373 nu positief geladen (protonering) en Lys gekoppeld aan Gln via een N-C(=O)⁻-binding op de plek van Cys314's S. De kandidaat moet links van de pijl de niet-bindende elektronenparen en de vloeipijlen (elektronenparen-verplaatsing) intekenen.$$, 'uitwerkbijlage');

insert into practice_questions (id, exercise_id, question_number, topics, question_image_url, question_text, context_block_ids) values
  ('456a7d54-2275-4fe9-aea5-93ff54f77b43', '874c5a66-d7e6-4c03-9886-4faf284c7faf', 1,
   '[{"domain": "Reacties", "subdomain": "Reactievergelijkingen opstellen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag1.png$$, $$Geef de vergelijking van deze vorming van cadmiumsulfide uit zwavel en cadmiumcarbonaat.$$, array['da96ea1c-1531-497d-86e1-863dc1bf6135']::uuid[]),
  ('40f3826c-0a1f-4413-b521-22aa811d4145', '874c5a66-d7e6-4c03-9886-4faf284c7faf', 2,
   '[{"domain": "Rekenen en analyse", "subdomain": "Molaire massa en molariteit"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag2.png$$, $$Bereken de massa in gram zwavel die minimaal nodig is om 1,0 kg cadmiumcarbonaat volledig om te zetten tot cadmiumsulfide. Geef de uitkomst in het juiste aantal significante cijfers.$$, array['da96ea1c-1531-497d-86e1-863dc1bf6135']::uuid[]),
  ('d691c43a-698b-4584-ac43-fbd52048f198', '874c5a66-d7e6-4c03-9886-4faf284c7faf', 3,
   '[{"domain": "Materie", "subdomain": "Bindingen en stofeigenschappen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag3.png$$, $$Leg uit dat zwavel bij een lagere temperatuur verdampt dan cadmiumsulfide. Neem hier aan dat zwavel bestaat uit deeltjes S₈.
− Gebruik hierbij begrippen op microniveau.
− Benoem de bindingstypes in beide stoffen.$$, array['a84b2616-09c0-4bb7-bdfb-09f0283c30fb']::uuid[]),
  ('a791380f-ca6c-41dd-93f7-dad0825df484', '874c5a66-d7e6-4c03-9886-4faf284c7faf', 4,
   '[{"domain": "Reacties", "subdomain": "Reactievergelijkingen opstellen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag4.png$$, $$Geef de vergelijking van de omzetting van cadmiumgeel tot cadmiumsulfaatmonohydraat.$$, array['da96ea1c-1531-497d-86e1-863dc1bf6135', '921fbfdd-039e-4eba-9b60-cdee131f6e31']::uuid[]),
  ('90c11665-36f7-4bb2-8336-ad879d7334db', '874c5a66-d7e6-4c03-9886-4faf284c7faf', 5,
   '[{"domain": "Materie", "subdomain": "Bindingen en stofeigenschappen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag5.png$$, $$Geef een mogelijke verhoudingsformule van het gevonden zout.$$, array['c7e5eca6-d2d5-476b-bf33-064bdc31a848']::uuid[]),
  ('b1e5efaa-05f3-44fe-a3fa-bc0c88efd6fb', '874c5a66-d7e6-4c03-9886-4faf284c7faf', 6,
   '[{"domain": "Reacties", "subdomain": "Chemisch evenwicht en evenwichtsconstante"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag6.png$$, $$Leg uit, onder andere met behulp van evenwichtsbeschouwingen, dat lood(II)sulfaat aanwezig is in de vernislaag als gevolg van periodes met hoge luchtvochtigheid. Neem aan dat de waardes in de tabel ook gelden onder de omstandigheden in een verflaag tijdens periodes van hoge luchtvochtigheid.$$, array['5a6d226d-de77-48bd-afa4-30c9ebc2f487', '337e2188-e2c3-4a38-83d3-a3ba976a2854', 'ecba17c7-eae8-46ce-8aaa-623785f0e9bb']::uuid[]),
  ('00ab02dc-626b-4a82-8700-94f439892f64', 'd9ad7f03-526a-4e52-90e0-0fd7c02ff730', 7,
   '[{"domain": "Rekenen en analyse", "subdomain": "Scheidingstechnieken (filteren, destilleren, extraheren)"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-vraag7.png$$, $$Geef de naam van de scheidingsmethode die wordt toegepast in R1.$$, array['945681b5-7e82-4fea-ada8-d36b0cb99c43', '5c8d1192-ad42-48c1-bbc2-f71cc3e28d0c']::uuid[]),
  ('da7d40b9-33be-4b6b-b11c-3646d95e06a0', 'd9ad7f03-526a-4e52-90e0-0fd7c02ff730', 8,
   '[{"domain": "Materie", "subdomain": "Bindingen en stofeigenschappen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-vraag8.png$$, $$Voer de volgende opdrachten uit:
− Leg uit dat het niet mogelijk is om lpg en R–SH te scheiden met behulp van water.
− Leg uit dat de scheiding in R1 wel mogelijk is in een basische oplossing. Benoem hierbij het bindingstype / de bindingtypes die een rol speelt/spelen bij de scheiding.$$, array['fa4d94be-06ee-48ff-a289-a785cb5ec4b1', '5c8d1192-ad42-48c1-bbc2-f71cc3e28d0c', '08f0184e-42f6-4ec8-aed3-601914a56858']::uuid[]),
  ('12406426-8f21-4902-8105-fc5bd80137ca', 'd9ad7f03-526a-4e52-90e0-0fd7c02ff730', 9,
   '[{"domain": "Reacties", "subdomain": "Reactievergelijkingen opstellen"}, {"domain": "Reacties", "subdomain": "Redoxreacties en elektrochemische cel"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-vraag9.png$$, $$Geef de vergelijking van de reactie die verloopt in R2.$$, array['5c8d1192-ad42-48c1-bbc2-f71cc3e28d0c', 'b09fd788-0429-4c00-8bc4-e1c9c8345a67']::uuid[]),
  ('19daee4c-50a6-4fa8-a857-8239077965c6', 'd9ad7f03-526a-4e52-90e0-0fd7c02ff730', 10,
   '[{"domain": "Rekenen en analyse", "subdomain": "Molaire massa en molariteit"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-vraag10.png$$, $$Bereken met behulp van figuur 2 de gemiddelde omzettingssnelheid van butaanthiol in mol L⁻¹ s⁻¹ tussen t = 0 en t = 2,0 h. Geef de uitkomst in het juiste aantal significante cijfers.$$, array['9626e0ef-c22d-4450-ad64-6de09328054e', '90b43e4a-17f1-48d6-9111-6243682892ce', '5a18e3c5-3439-4080-ad6f-f1fb4d3a15ad']::uuid[]),
  ('146e66df-fc1e-4109-a17b-4f942f007d36', 'd9ad7f03-526a-4e52-90e0-0fd7c02ff730', 11,
   '[{"domain": "Technologie en duurzaamheid", "subdomain": "Reactoren en scheidingsinstallaties"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-vraag11.png$$, $$Leg uit welke bewerking het natronloog moet ondergaan voordat het kan worden teruggevoerd.$$, array['5c8d1192-ad42-48c1-bbc2-f71cc3e28d0c', 'c43ab995-262c-4779-b564-63b2f25a09f4']::uuid[]),
  ('6b6fa099-c7ad-4e67-a86a-3b6abdf667c5', 'd9ad7f03-526a-4e52-90e0-0fd7c02ff730', 12,
   '[{"domain": "Technologie en duurzaamheid", "subdomain": "Blokschema van een chemisch proces"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-vraag12.png$$, $$Maak het blokschema op de uitwerkbijlage compleet.
− Teken de ontbrekende scheidingsruimte(n).
− Teken ontbrekende stofstromen. Houd hierbij rekening met hergebruik van stoffen.
− Waar in het blokschema een * voorkomt, hoef je niets aan te geven.$$, array['945681b5-7e82-4fea-ada8-d36b0cb99c43', 'b09fd788-0429-4c00-8bc4-e1c9c8345a67', 'c43ab995-262c-4779-b564-63b2f25a09f4', '40f37add-3ca6-40f6-bdf6-dd008c5ef4aa']::uuid[]),
  ('21b8e4b7-0492-4cfa-9fa3-6909f740e8af', '4333ac2f-7634-4431-ab1c-cc3f891ad404', 13,
   '[{"domain": "Materie", "subdomain": "Polymeren, legeringen en keramische materialen"}, {"domain": "Reacties", "subdomain": "Polymerisatie"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-vraag13.png$$, $$Teken de structuurformule van een gedeelte van een molecuul t-EPDM. Dit gedeelte moet komen uit het midden van een molecuul en moet bestaan uit één eenheid van etheen, propeen en ENB.$$, array['7aa8e786-010d-45ad-8fe7-e8183b1a8005']::uuid[]),
  ('7c0468f7-10f4-46cc-b96d-876bcbb8f9d0', '4333ac2f-7634-4431-ab1c-cc3f891ad404', 14,
   '[{"domain": "Materie", "subdomain": "Polymeren, legeringen en keramische materialen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-vraag14.png$$, $$Leg uit of toepassing van een katalysator type 2 bij de polymerisatie leidt tot een groter of kleiner percentage kristallijne gebieden. Gebruik hierbij Binas-tabel 66F of ScienceData-tabel 11.1.3.$$, array['8130899a-7424-40f8-a41e-52a434e355b6']::uuid[]),
  ('b77f5c5c-d1e9-4a1e-9dd4-207ec88c76a2', '4333ac2f-7634-4431-ab1c-cc3f891ad404', 15,
   '[{"domain": "Materie", "subdomain": "Polymeren, legeringen en keramische materialen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-vraag15.png$$, $$Leg uit dat t-EPDM met een groot percentage kristallijne gebieden een kleinere vervormbaarheid heeft dan t-EPDM met een klein percentage kristallijne gebieden. Gebruik hierbij begrippen op microniveau.$$, array['8130899a-7424-40f8-a41e-52a434e355b6', 'cc8feedf-7b56-4991-978e-f65971e02a75']::uuid[]),
  ('7e7cffbd-e9c3-46a9-8f22-615de2a2bca7', '4333ac2f-7634-4431-ab1c-cc3f891ad404', 16,
   '[{"domain": "Rekenen en analyse", "subdomain": "Koolstof- en stikstofkringloop"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-vraag16.png$$, $$Leg uit of het gehalte ¹⁴C in Keltan®-Eco hoger of lager is dan in EPDM-rubber dat is geproduceerd op basis van fossiele grondstoffen.$$, array['991e5cab-3f0f-4edb-99e2-69709163eb6d', '92eca182-78bc-4430-940d-acc9c6f0ff6e']::uuid[]),
  ('fed1741c-b9ef-474e-912d-a9e08135e699', '4333ac2f-7634-4431-ab1c-cc3f891ad404', 17,
   '[{"domain": "Reacties", "subdomain": "Exotherme en endotherme reacties"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-vraag17.png$$, $$Bereken de massa in kilogram suikerriet-resten die nodig is om de energie te leveren voor de omzetting van 1,0 ton ethanol tot etheen.
− Gebruik Binas-tabel 28B en 57 of ScienceData-tabel 8.7b en 9.2.
− Neem aan dat de suikerriet-resten volledig bestaan uit hout.
− Een ton is 10³ kg.$$, array['991e5cab-3f0f-4edb-99e2-69709163eb6d', 'ab78dbed-09a0-48ab-8710-4bc8f4fc4310']::uuid[]),
  ('a3e5d56c-a434-450e-a97a-21da4dc428c2', '4333ac2f-7634-4431-ab1c-cc3f891ad404', 18,
   '[{"domain": "Materie", "subdomain": "Bindingen en stofeigenschappen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-vraag18.png$$, $$Teken op de uitwerkbijlage hoe een molecuul ethanol met twee waterstofbruggen gebonden is aan het oppervlak. Geef elke waterstofbrug weer met een stippellijn.$$, array['ed280bf7-cb07-4afa-8517-aaed4f2a08a2', '35703a2d-59f9-4c52-be89-f9edf51537c5']::uuid[]),
  ('856e7f86-fbd7-4340-9b8d-de9b1bd58920', '4333ac2f-7634-4431-ab1c-cc3f891ad404', 19,
   '[{"domain": "Rekenen en analyse", "subdomain": "Molaire massa en molariteit"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-vraag19.png$$, $$Bereken het volume in liter propeen dat minimaal nodig is om 1,0 kg Keltan®-Eco te produceren. Gebruik hierbij onder andere de volgende gegevens:
− De dichtheid van propeen is 1,75 kg m⁻³.
− De gemiddelde molaire massa van een monomeereenheid van Keltan®-Eco is 38,3 g mol⁻¹.$$, array['ff8dbac0-148f-4370-a07c-df77e634cc73']::uuid[]),
  ('b1d21d8c-dfee-4c44-9cc1-dbaafaaa02c1', 'acda46bd-f2b7-40ab-bf46-332fcd744f86', 20,
   '[{"domain": "Materie", "subdomain": "Moleculaire structuur en ruimtelijke bouw"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-vraag20.png$$, $$Leg uit, aan de hand van deze gegevens, of door deze omzetting de primaire structuur van de peptideketens in de eiwitten verloren gaat.$$, array['39446b8a-1a4f-493d-b107-4c4408e2dca4']::uuid[]),
  ('2fd37a16-b8c1-4948-9d64-badb2342e899', 'acda46bd-f2b7-40ab-bf46-332fcd744f86', 21,
   '[{"domain": "Reacties", "subdomain": "Reactievergelijkingen opstellen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-vraag21.png$$, $$Geef de formule van het deeltje X.$$, array['74268463-44b3-4a91-b8e7-9eb5554f89ac', 'a06623e5-d83a-40b3-a476-05ca61a9878c']::uuid[]),
  ('9635c9a4-143b-4a8c-88a0-a29902285af4', 'acda46bd-f2b7-40ab-bf46-332fcd744f86', 22,
   '[{"domain": "Reacties", "subdomain": "Reactievergelijkingen opstellen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-vraag22.png$$, $$Maak de vergelijking op de uitwerkbijlage compleet en geef de naam van de aminozuureenheid die hierbij wordt gevormd.$$, array['f7b7ae9f-96e1-4253-af2a-3f370ab0d87b', '5e6f6452-42ff-4a31-847a-6d83bc027341']::uuid[]),
